INSERT INTO `document_vectors` VALUES (454, 'fa684e3ded389a52f456741890c23856', 90, '\'æ�¹å½¢é��æµ�å¼�å�·å�´å¡�\' \'default_url\' \'default_url\' \'\' \'\' \'é£�æ�ºç�´å¾�\' \'\' \'å¡�ä½�è¾¹é�¿\' \'è§�æ ¼ç­�çº§\' \'Lï¼�ä½�å�ªé�³Uï¼�è¶�ä½�å�ªé�³LGï¼�å�¨é�¢ä½�å�ªé�³UGï¼�å�¨é�¢è¶�ä½�å�ªé�³LSï¼�å��ä¸�é��é�¢ä½�å�ªé�³USï¼�å��ä¸�é��é�¢è¶�ä½�å�ªé�³LSSï¼�å�¨ä¸�é��é�¢ä½�å�ªé�³USSï¼�å�¨ä¸�é��é�¢è¶�ä½�å�ªé�³\' \'\' \'\' \'\' \'\' \'\' \'\' \'\');INSERT INTO cooling_tower_specifications (model photo_url flow head length width height fan_diameter motor spray_pump net_weight operating_weight inlet_piping outlet_piping_dn makeup_piping_dn ', NULL, '1', 'DEFAULT', 0);
