INSERT INTO `document_vectors` VALUES (1090, '569c6c6941efa008a3dc5c72dace414e', 1, '1.cpu\r\n2.没有pth文件\r\n3.log文件冲突\r\n4.cuda问题\r\n5.你提供的代码片段展示了如何计算边界框的位置，并准备为图像上的检测结果添加标签。然而，正如之前提到的，draw.textsize() 方法在 Pillow 版本 10.0.0 及以上中已经被移除了。如果你正在使用的是较新版本的 Pillow，你需要更新这部分代码以避免 AttributeError。', NULL, '2', 'PRIVATE_caiyuping', 0);
INSERT INTO `document_vectors` VALUES (1091, '569c6c6941efa008a3dc5c72dace414e', 2, '\r\n\r\n这里是如何修改你的代码来兼容新版本的 Pillow：\r\n\r\npython\r\n编辑\r\nfrom PIL import ImageFont\r\n\r\n# 假设 font 已经定义好\r\n# 如果没有定义，可以这样创建一个字体对象\r\n# font = ImageFont.load_default() 或者指定 ttf 文件路径加载自定义字体\r\n# font = ImageFont.truetype(\"path/to/your/font.ttf\", size=...)\r\n\r\ntop = max(0, np.floor(top).astype(\'int32\'))\r\nleft = max(0, np.floor(left).astype(\'int32\'))\r\nbottom = min(image.size[1], np.floor(bottom).astype(\'int32\'))\r\nright = min(image.size[0], np.floor(right).astype(\'int32\'))\r\n\r\nlabel = \'{} {:.2f}\'.format(predicted_class, score)\r\ndraw ', NULL, '2', 'PRIVATE_caiyuping', 0);
INSERT INTO `document_vectors` VALUES (1092, '569c6c6941efa008a3dc5c72dace414e', 3, '= ImageDraw.Draw(image)\r\n\r\n# 替换旧方法\r\ntry:\r\n    # For Pillow >= 10.0\r\n    left_bbox, top_bbox, right_bbox, bottom_bbox = draw.textbbox((0, 0), label, font=font)\r\n    label_size = (right_bbox - left_bbox, bottom_bbox - top_bbox)\r\nexcept AttributeError:\r\n    # For older versions of Pillow\r\n    label_size = draw.textsize(label, font)\r\n\r\nlabel = label.encode(\'utf-8\')\r\nprint(label, top, left, bottom, right)\r\n请注意，为了使 draw.textbbox() 方法工作，你需要确保 font 对象已经正确定义。', NULL, '2', 'PRIVATE_caiyuping', 0);
INSERT INTO `document_vectors` VALUES (1093, '569c6c6941efa008a3dc5c72dace414e', 4, '如果未定义，可以通过 ImageFont.load_default() 使用默认字体，或者通过 ImageFont.truetype() 方法加载自定义字体文件。\r\n\r\n这种方法首先尝试使用 textbbox() 获取文本尺寸，它适用于 Pillow 10.0.0 及以上版本。如果当前环境中的 Pillow 版本不支持 textbbox() 方法，则会捕获异常并使用原来的 textsize() 方法获取文本尺寸。这样就能确保代码在不同版本的 Pillow 上都能正常运行。', NULL, '2', 'PRIVATE_caiyuping', 0);
INSERT INTO `document_vectors` VALUES (1094, '50033799247d5d97d87316fa64cb9e8c', 1, '小明是一名数据科学专业的学生，平日里最爱钻研 Java 和 Spring 框架。有一次，他在调试 RPC 框架时遇到了配置加载失败的难题，对着代码苦思冥想了整整一个深夜。就在窗外晨光初露时，他突然发现是一个依赖包导入错误，修改后程序完美运行。他开心地合上电脑，满怀成就感地迎接新的一天。', NULL, '1', 'DEFAULT', 1);
INSERT INTO `document_vectors` VALUES (1095, '6a2c8d8c91c6d6cea08ef2b2c3184417', 1, '小明的故事是一名数据科学专业的学生，平日里最爱钻研 Java 和 Spring 框架。有一次，他在调试 RPC 框架时遇到了配置加载失败的难题，对着代码苦思冥想了整整一个深夜。就在窗外晨光初露时，他突然发现是一个依赖包导入错误，修改后程序完美运行。他开心地合上电脑，满怀成就感地迎接新的一天。', NULL, '1', 'admin', 0);
